class Solution {
public:
    vector<string> uncommonFromSentences(string s1, string s2) {
        unordered_map<string,int> freq;
        auto add = [&](const string& s){
            stringstream ss(s);
            string w;
            while(ss>>w) ++freq[w];
        };
        add(s1); add(s2);
        vector<string> res;
        for(auto& [w,c]:freq) if(c==1) res.push_back(w);
        return res;
    }
};
